#include <vector>
#include <string>
#include <algorithm>

class Solution {
public:
    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {
        vector<int> result;
        sort(nums.begin(), nums.end());
        for (int i = 0; i < queries.size(); i++) {
            int k = queries[i][0];
            int trim = queries[i][1];
            result.push_back(find(nums.begin(), nums.end(), nums[k - trim]);
        }
        return result;
    }
};
